// 7-Segment Counter: press button to increment 0-9, wraps back to 0
// Segments: a=6, b=7, c=8, d=9, e=10, f=11, g=12
// Button: D2 (INPUT_PULLUP, other side to GND)

const int SEG_A = 6;
const int SEG_B = 7;
const int SEG_C = 8;
const int SEG_D = 9;
const int SEG_E = 10;
const int SEG_F = 11;
const int SEG_G = 12;
const int BTN_PIN = 2;

int count = 0;
int lastBtnState = HIGH;

// Display a digit 0-9 on the 7-segment (common cathode, active HIGH)
void showDigit(int n) {
  int a, b, c, d, e, f, g;
  if (n == 0) { a=1; b=1; c=1; d=1; e=1; f=1; g=0; }
  else if (n == 1) { a=0; b=1; c=1; d=0; e=0; f=0; g=0; }
  else if (n == 2) { a=1; b=1; c=0; d=1; e=1; f=0; g=1; }
  else if (n == 3) { a=1; b=1; c=1; d=1; e=0; f=0; g=1; }
  else if (n == 4) { a=0; b=1; c=1; d=0; e=0; f=1; g=1; }
  else if (n == 5) { a=1; b=0; c=1; d=1; e=0; f=1; g=1; }
  else if (n == 6) { a=1; b=0; c=1; d=1; e=1; f=1; g=1; }
  else if (n == 7) { a=1; b=1; c=1; d=0; e=0; f=0; g=0; }
  else if (n == 8) { a=1; b=1; c=1; d=1; e=1; f=1; g=1; }
  else           { a=1; b=1; c=1; d=1; e=0; f=1; g=1; } // 9

  digitalWrite(SEG_A, a);
  digitalWrite(SEG_B, b);
  digitalWrite(SEG_C, c);
  digitalWrite(SEG_D, d);
  digitalWrite(SEG_E, e);
  digitalWrite(SEG_F, f);
  digitalWrite(SEG_G, g);
}

void setup() {
  pinMode(SEG_A, OUTPUT);
  pinMode(SEG_B, OUTPUT);
  pinMode(SEG_C, OUTPUT);
  pinMode(SEG_D, OUTPUT);
  pinMode(SEG_E, OUTPUT);
  pinMode(SEG_F, OUTPUT);
  pinMode(SEG_G, OUTPUT);
  pinMode(BTN_PIN, INPUT_PULLUP);
  showDigit(0);
}

void loop() {
  int btnState = digitalRead(BTN_PIN);

  // Detect falling edge (button pressed)
  if (btnState == LOW && lastBtnState == HIGH) {
    count = count + 1;
    if (count > 9) {
      count = 0;
    }
    showDigit(count);
    delay(50); // debounce
  }

  lastBtnState = btnState;
  delay(10);
}

